import React from "https://esm.sh/react@18.2.0";
import ReactDOM from "https://esm.sh/react-dom@18.2.0";

function App() {
  const filters = appsmith.model?.filters || [];

  let year = "All time";
  let locations = "All Locations";
  let utilityType = "All Utilities";

  filters.forEach((filter) => {
    if (filter.filter === "year" && filter.year?.year) year = filter.year.year;
    if (filter.filter === "locations" && filter.locations?.name) locations = filter.locations.name;
    if (filter.filter === "utility_type" && filter.utility_type?.type) utilityType = filter.utility_type.type;
  });

  const labels = ["Year", "Locations", "Utility Type"];
  const values = [year, locations, utilityType];

  return (
    <div className="container">
      <div className="row labels">
        {labels.map((label) => (
          <div className="cell" key={label}>{label}:</div>
        ))}
      </div>
      <div className="row values">
        {values.map((value, i) => (
          <div className="cell" key={i}>{value}</div>
        ))}
      </div>
    </div>
  );
}

appsmith.onReady(() => {
  ReactDOM.render(<App />, document.getElementById("root"));
});
